public void FormatConnectionString_ProducesExpectedFormat()
{
    var config = new AppConfig();
    config.Set("Host", "localhost");
    config.Set("Port", "5432");
    config.Set("Database", "mydb");
    var result = config.FormatConnectionString();
    StringAssert.Contains(result, "Host=localhost");
    StringAssert.Contains(result, "Port=5432");
    Assert.AreEqual("Host=localhost;Port=5432;Database=mydb", result);
}
```

**4. Add a clone independence test:**
